```cpp
#pragma once

#include <reaction/reaction.h>
#include <string>
#include <unordered_set>

namespace test_reaction {

class NamedObserverNode : public reaction::ObserverNode {
public:
    explicit NamedObserverNode(std::string name) : m_name(std::move(name)) {}
    const std::string& name() const { return m_name; }

private:
    std::string m_name;
};

struct ObserverCollectionSummary {
    std::size_t totalObservers;
    bool containsDirectObserver;
    bool containsTransitiveObserver;
};

ObserverCollectionSummary test_observer_collection() {
    // 1. Create NamedObserverNode instances
    auto root = std::make_shared<NamedObserverNode>("root");
    auto direct_observer = std::make_shared<NamedObserverNode>("direct");
    auto transitive_observer = std::make_shared<NamedObserverNode>("transitive");

    // 2. Get observer graph instance
    auto& observer_graph = reaction::ObserverGraph::getInstance();

    // 3. Register nodes
    observer_graph.registerNode(root);
    observer_graph.registerNode(direct_observer);
    observer_graph.registerNode(transitive_observer);

    // 4. Set up direct observer relationship: root observes direct_observer
    observer_graph.addObserver(root, direct_observer);

    // 5. Set up transitive observer relationship: direct_observer observes transitive_observer
    observer_graph.addObserver(direct_observer, transitive_observer);

    // 6. Create NodeSet to store collected observers
    reaction::ObserverGraph::NodeSet observers_set;

    // 7. Collect observers starting from root node
    observer_graph.collectObservers(root, observers_set);

    // 8. Check if direct observer is in collected set
    bool contains_direct = false;
    for (const auto& observer : observers_set) {
        if (observer.lock() == direct_observer) {
            contains_direct = true;
            break;
        }
    }

    // 9. Check if transitive observer is in collected set  
    bool contains_transitive = false;
    for (const auto& observer : observers_set) {
        if (observer.lock() == transitive_observer) {
            contains_transitive = true;
            break;
        }
    }

    // 10. Return collection summary
    return ObserverCollectionSummary{
        observers_set.size(),
        contains_direct,
        contains_transitive
    };
}

}  // namespace test_reaction
```

